// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.OptionalLong;
import java.util.Set;

import org.eclipse.rdf4j.benchmark.common.ThemeQueryCatalog;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.rio.helpers.AbstractRDFHandler;
import org.junit.jupiter.api.Test;

/**
 * Pins the theme-benchmark catalog's expected ?count for LIBRARY query 9 ("members borrowing books by authors") to the
 * ground truth computed directly from the deterministic generated dataset with plain Java collections — no query engine
 * involved. Every engine configuration (native on/off, sketches on/off) has always answered 2 for this query while the
 * catalog expected 0; this test proves 2 is correct: the generator's due dates all lie on or after 2024-01-15 (loan
 * date starts 2024-01-01 and dueDate = loanDate + 14 days), so the NOT EXISTS cutoff of 2024-01-10 filters nothing, and
 * exactly two members borrow books by "Author 1"/"Author 2"/"Author 3".
 *
 * Query semantics replayed: COUNT(DISTINCT ?member) over member/loan/copy/book/author joins where the author name
 * matches the VALUES/disjunct set, the loan has NO dueDate earlier than 2024-01-10 (NOT EXISTS), and the book's title
 * is a bound, non-empty string (OPTIONAL + FILTER(?optTitle != "") — an unbound ?optTitle is a type error and drops the
 * row).
 */
public class LmdbLibraryQ9CatalogExpectationTest {

	private static final String LIB = "http://example.com/theme/library/";

	@Test
	public void catalogExpectationMatchesDatasetGroundTruth() {
		IRI memberType = iri("Member");
		IRI loanType = iri("Loan");
		IRI borrowedBy = iri("borrowedBy");
		IRI loanedCopy = iri("loanedCopy");
		IRI hasCopy = iri("hasCopy");
		IRI writtenBy = iri("writtenBy");
		IRI name = iri("name");
		IRI title = iri("title");
		IRI dueDate = iri("dueDate");

		Set<Value> members = new HashSet<>();
		Set<Value> loans = new HashSet<>();
		Map<Value, Set<Value>> loanToMembers = new HashMap<>();
		Map<Value, Set<Value>> loanToCopies = new HashMap<>();
		Map<Value, Set<Value>> copyToBooks = new HashMap<>();
		Map<Value, Set<Value>> bookToAuthors = new HashMap<>();
		Map<Value, Set<String>> authorNames = new HashMap<>();
		Map<Value, Set<String>> bookTitles = new HashMap<>();
		Map<Value, Set<String>> loanDueDates = new HashMap<>();

		ThemeDataSetGenerator.generate(Theme.LIBRARY, new AbstractRDFHandler() {
			@Override
			public void handleStatement(Statement st) {
				Resource s = st.getSubject();
				IRI p = st.getPredicate();
				Value o = st.getObject();
				if (p.equals(RDF.TYPE)) {
					if (o.equals(memberType)) {
						members.add(s);
					} else if (o.equals(loanType)) {
						loans.add(s);
					}
				} else if (p.equals(borrowedBy)) {
					loanToMembers.computeIfAbsent(s, k -> new HashSet<>()).add(o);
				} else if (p.equals(loanedCopy)) {
					loanToCopies.computeIfAbsent(s, k -> new HashSet<>()).add(o);
				} else if (p.equals(hasCopy)) {
					copyToBooks.computeIfAbsent(o, k -> new HashSet<>()).add(s);
				} else if (p.equals(name)) {
					authorNames.computeIfAbsent(s, k -> new HashSet<>()).add(((Literal) o).getLabel());
				} else if (p.equals(writtenBy)) {
					bookToAuthors.computeIfAbsent(s, k -> new HashSet<>()).add(o);
				} else if (p.equals(title)) {
					bookTitles.computeIfAbsent(s, k -> new HashSet<>()).add(((Literal) o).getLabel());
				} else if (p.equals(dueDate)) {
					loanDueDates.computeIfAbsent(s, k -> new HashSet<>()).add(((Literal) o).getLabel());
				}
			}
		});

		Set<String> targetNames = Set.of("Author 1", "Author 2", "Author 3");
		String cutoff = "2024-01-10"; // ISO dates compare correctly as strings

		Set<Value> qualifying = new HashSet<>();
		for (Value loan : loans) {
			// NOT EXISTS { ?loan lib:dueDate ?due . FILTER(?due < cutoff) }
			boolean anyOverdue = loanDueDates.getOrDefault(loan, Set.of())
					.stream()
					.anyMatch(d -> d.compareTo(cutoff) < 0);
			if (anyOverdue) {
				continue;
			}
			for (Value member : loanToMembers.getOrDefault(loan, Set.of())) {
				if (!members.contains(member)) {
					continue;
				}
				for (Value copy : loanToCopies.getOrDefault(loan, Set.of())) {
					for (Value book : copyToBooks.getOrDefault(copy, Set.of())) {
						// FILTER(?optTitle != "") over the OPTIONAL title: needs a bound non-empty title
						boolean titleOk = bookTitles.getOrDefault(book, Set.of())
								.stream()
								.anyMatch(t -> !t.isEmpty());
						if (!titleOk) {
							continue;
						}
						for (Value author : bookToAuthors.getOrDefault(book, Set.of())) {
							boolean nameOk = authorNames.getOrDefault(author, Set.of())
									.stream()
									.anyMatch(targetNames::contains);
							if (nameOk) {
								qualifying.add(member);
							}
						}
					}
				}
			}
		}

		OptionalLong catalogExpectation = ThemeQueryCatalog.expectedCountBindingValueFor(Theme.LIBRARY, 9);
		assertThat(catalogExpectation)
				.as("catalog expected ?count for LIBRARY query 9")
				.hasValue(qualifying.size());
	}

	private static IRI iri(String local) {
		return SimpleValueFactory.getInstance().createIRI(LIB, local);
	}
}
